function normalizeDateInput(value) {
    const text = String(value || "").trim();
    if (!text) return "";
    if (/^\d{4}-\d{2}-\d{2}$/.test(text)) return text;
    const parsed = new Date(text);
    if (Number.isNaN(parsed.getTime())) return "";
    return parsed.toISOString().slice(0, 10);
}


function bootstrapNormalizeEmail(value) {
    return String(value || "").trim().toLowerCase();
}

function bootstrapNormalizeFreeText(value) {
    return String(value || "").trim().replace(/\s+/g, " ");
}

function escapeHtml(value) {
    return String(value || "")
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#39;");
}

function stripEnvWrappingQuotes(value) {
    const text = String(value || "").trim();
    if (!text) return "";
    if ((text.startsWith('"') && text.endsWith('"')) || (text.startsWith("'") && text.endsWith("'"))) {
        return text.slice(1, -1).trim();
    }
    return text;
}

function normalizeSmtpPassword(host, password) {
    const text = String(password || "");
    return /(^|\.)gmail\.com$/i.test(String(host || "").trim())
        ? text.replace(/\s+/g, "")
        : text;
}

function readEnv(name, fallback = "") {
    const value = Object.prototype.hasOwnProperty.call(process.env, name)
        ? process.env[name]
        : fallback;
    return stripEnvWrappingQuotes(value);
}

function readBooleanEnv(name, fallback = false) {
    const value = readEnv(name, fallback ? "true" : "false");
    return /^(1|true|yes|on)$/i.test(value);
}

