function validateProductionEnvironment(env = process.env) {
    const isProduction = normalizeFreeText(env.NODE_ENV || "").toLowerCase() === "production";
    if (!isProduction) return [];
    const missing = [];
    if (!stripEnvWrappingQuotes(env.APP_ADMIN_EMAIL || "")) missing.push("APP_ADMIN_EMAIL");
    if (!stripEnvWrappingQuotes(env.APP_ADMIN_PASSWORD || "")) missing.push("APP_ADMIN_PASSWORD");
    if (!stripEnvWrappingQuotes(env.DATABASE_PRIVATE_URL || env.DATABASE_URL || "")) missing.push("DATABASE_URL or DATABASE_PRIVATE_URL");
    if (!stripEnvWrappingQuotes(env.INTEGRATION_SECRET_KEY || env.APP_SECRET || env.SESSION_SECRET || "")) {
        missing.push("INTEGRATION_SECRET_KEY or APP_SECRET");
    }
    const forbiddenEmailConfig = getForbiddenOutboundEmailConfig(env);
    if (forbiddenEmailConfig.length) {
        missing.push(`Remove forbidden outbound email sender: ${forbiddenEmailConfig.join(", ")}`);
    }
    return missing;
}

function normalizeEmailIdentity(value) {
    const text = stripEnvWrappingQuotes(value || "");
    if (!text) return "";
    const match = text.match(/<([^>]+)>/);
    return normalizeEmail(match?.[1] || text);
}

function isForbiddenOutboundEmailSender(value) {
    const email = normalizeEmailIdentity(value);
    return !!email && FORBIDDEN_OUTBOUND_EMAIL_SENDERS.has(email);
}

function getForbiddenOutboundEmailConfig(env = process.env) {
    return [
        ["SMTP_USER", env.SMTP_USER],
        ["SMTP_FROM", env.SMTP_FROM],
        ["SMTP_REPLY_TO", env.SMTP_REPLY_TO],
        ["EMAIL_FROM", env.EMAIL_FROM],
        ["MAIL_FROM", env.MAIL_FROM]
    ]
        .filter(([, value]) => isForbiddenOutboundEmailSender(value))
        .map(([name]) => name);
}

function sanitizeSensitiveLogMessage(value) {
    return String(value || "")
        .replace(/(access[_-]?token|api[_-]?key|client[_-]?secret|password|authorization)(=|:)\s*[^&\s|]+/gi, "$1$2 [redacted]")
        .replace(/Bearer\s+[A-Za-z0-9._~+/=-]+/gi, "Bearer [redacted]");
}

function assertProductionEnvironment(env = process.env) {
    const missing = validateProductionEnvironment(env);
    if (missing.length) {
        throw new Error(`Production startup blocked. Missing required environment: ${missing.join(", ")}`);
    }
}

try {
    if (require.main === module) {
        assertProductionEnvironment(process.env);
    }
} catch (error) {
    console.error(error.message || error);
    process.exit(1);
}

const pool = DATABASE_URL
    ? new Pool({
        connectionString: DATABASE_URL,
        ssl: shouldUseSsl(DATABASE_URL) ? { rejectUnauthorized: false } : false,
        connectionTimeoutMillis: DATABASE_CONNECTION_TIMEOUT_MS,
        idleTimeoutMillis: 30000
    })
    : createUnavailablePool("DATABASE_URL or DATABASE_PRIVATE_URL is required. Add a PostgreSQL database in Railway and expose it to this service.");

if (!DATABASE_URL) {
    databaseErrorMessage = "DATABASE_URL or DATABASE_PRIVATE_URL is required. Add a PostgreSQL database in Railway and expose it to this service.";
    if (require.main === module) {
        console.error(databaseErrorMessage);
    }
}

pool.on("error", (error) => {
    databaseReady = false;
    databaseErrorMessage = error.message;
    console.error("Unexpected PostgreSQL pool error:", sanitizeSensitiveLogMessage(error.message || "database error"));
});

