app.post("/api/admin/system-email/test", async (req, res, next) => {
    try {
        assertSuperAdminAccess(req.appUser);
        const defaultRecipient = req.appUser?.email || DEFAULT_ADMIN_EMAIL;
        const recipients = normalizeEmailList(req.body?.recipient || req.body?.to || defaultRecipient, { throwOnInvalid: true });
        if (!recipients.length) {
            throw httpError(400, "Enter an email address to receive the test message.");
        }

        const recipient = recipients[0];
        const now = new Date();
        const subject = `WMS365 system email test - ${APP_BUILD_INFO.deploymentRef}`;
        const provider = getConfiguredEmailProvider() || "Not configured";
        const lines = [
            "WMS365 system email test",
            "",
            "This confirms the configured WMS365 email provider can send email from the live app.",
            `Sent at: ${now.toISOString()}`,
            `Requested by: ${req.appUser?.email || "Unknown admin"}`,
            `Build: ${APP_BUILD_INFO.label}`,
            `Email provider: ${provider}`,
            SMTP_HOST ? `SMTP host: ${SMTP_HOST}:${SMTP_PORT}` : "",
            `From: ${SMTP_FROM}`,
            SMTP_REPLY_TO ? `Reply-To: ${SMTP_REPLY_TO}` : ""
        ].filter(Boolean);

        const emailResult = await sendSystemEmail({
            from: SMTP_FROM,
            to: recipient,
            replyTo: SMTP_REPLY_TO || undefined,
            subject,
            text: lines.join("\n"),
            html: `
                <div style="font-family:Arial,sans-serif;color:#111827;line-height:1.5;">
                    <h2 style="margin:0 0 12px;">WMS365 system email test</h2>
                    <p>This confirms the configured WMS365 email provider can send email from the live app.</p>
                    <table style="border-collapse:collapse;width:100%;max-width:720px;">
                        <tr><td style="padding:6px 0;font-weight:600;">Sent at</td><td style="padding:6px 0;">${escapeHtml(now.toISOString())}</td></tr>
                        <tr><td style="padding:6px 0;font-weight:600;">Requested by</td><td style="padding:6px 0;">${escapeHtml(req.appUser?.email || "Unknown admin")}</td></tr>
                        <tr><td style="padding:6px 0;font-weight:600;">Build</td><td style="padding:6px 0;">${escapeHtml(APP_BUILD_INFO.label)}</td></tr>
                        <tr><td style="padding:6px 0;font-weight:600;">Email provider</td><td style="padding:6px 0;">${escapeHtml(provider)}</td></tr>
                        ${SMTP_HOST ? `<tr><td style="padding:6px 0;font-weight:600;">SMTP host</td><td style="padding:6px 0;">${escapeHtml(`${SMTP_HOST}:${SMTP_PORT}`)}</td></tr>` : ""}
                        <tr><td style="padding:6px 0;font-weight:600;">From</td><td style="padding:6px 0;">${escapeHtml(SMTP_FROM)}</td></tr>
                        ${SMTP_REPLY_TO ? `<tr><td style="padding:6px 0;font-weight:600;">Reply-To</td><td style="padding:6px 0;">${escapeHtml(SMTP_REPLY_TO)}</td></tr>` : ""}
                    </table>
                </div>
            `,
            emailContext: {
                sourceType: "SYSTEM_EMAIL_TEST",
                sourceRef: APP_BUILD_INFO.deploymentRef
            }
        }, "System email is not configured. Set RESEND_API_KEY, SENDGRID_API_KEY, or SMTP settings first.");

        res.json({
            success: true,
            recipient,
            sentAt: now.toISOString(),
            from: SMTP_FROM,
            smtpHost: SMTP_HOST,
            emailProvider: emailResult.provider || provider,
            messageId: emailResult.messageId || ""
        });
    } catch (error) {
        next(error);
    }
});

app.get("/api/admin/system-email/queue", async (req, res, next) => {
    try {
        assertSuperAdminAccess(req.appUser);
        assertDatabaseAvailable();
        const status = normalizeEmailDeliveryStatus(req.query?.status || "");
        const search = normalizeFreeText(req.query?.search || req.query?.query || "").slice(0, 200);
        const limit = Math.min(Math.max(toPositiveInt(req.query?.limit) || 75, 1), 250);
        const params = [];
        const clauses = [];

        if (status) {
            params.push(status);
            clauses.push(`status = $${params.length}`);
        }
        if (search) {
            params.push(`%${search.toLowerCase()}%`);
            clauses.push(`(
                lower(subject) like $${params.length}
                or lower(account_name) like $${params.length}
                or lower(source_ref) like $${params.length}
                or lower(provider) like $${params.length}
                or lower(from_address) like $${params.length}
                or lower(to_addresses::text) like $${params.length}
                or lower(cc_addresses::text) like $${params.length}
                or lower(error_message) like $${params.length}
            )`);
        }

        params.push(limit);
        const whereSql = clauses.length ? `where ${clauses.join(" and ")}` : "";
        const result = await pool.query(
            `
                select *
                from email_delivery_log
                ${whereSql}
                order by created_at desc, id desc
                limit $${params.length}
            `,
            params
        );
        const summaryResult = await pool.query(`
            select status, count(*)::integer as count
            from email_delivery_log
            where created_at >= now() - interval '7 days'
            group by status
        `);
        const summary = { total: 0, pending: 0, sent: 0, failed: 0 };
        summaryResult.rows.forEach((row) => {
            const key = String(row.status || "").toLowerCase();
            const count = Number(row.count || 0);
            summary.total += count;
            if (key === "pending" || key === "sent" || key === "failed") summary[key] = count;
        });

        res.json({
            success: true,
            emails: result.rows.map(mapEmailDeliveryLogRow),
            summary,
            filters: { status, search, limit }
        });
    } catch (error) {
        next(error);
    }
});

