app.post("/api/admin/portal-access", async (req, res, next) => {
    try {
        const accessId = typeof req.body?.accessId === "string" || typeof req.body?.accessId === "number"
            ? String(req.body.accessId).trim()
            : "";
        const accountName = normalizeText(req.body?.accountName || req.body?.owner || req.body?.vendor || req.body?.customer);
        const email = normalizeEmail(req.body?.email);
        const password = typeof req.body?.password === "string" ? req.body.password : "";
        const isActive = req.body?.isActive !== false;
        const sendWelcomeEmail = req.body?.sendWelcomeEmail !== false;
        const portalPermissions = req.body?.portalPermissions || req.body?.portal_permissions || req.body?.permissions || null;

        if (!accountName) {
            throw httpError(400, "Company is required.");
        }
        if (!email) {
            throw httpError(400, "A user email address is required.");
        }

        const savedAccess = await withTransaction(async (client) => {
            await assertAppUserCompanyAccess(client, req.appUser, accountName);
            await assertCompanyFeatureEnabled(client, accountName, COMPANY_FEATURE_KEYS.CUSTOMER_PORTAL);
            await upsertOwnerMaster(client, accountName);
            const access = await savePortalAccess(client, { accessId, accountName, email, password, isActive, portalPermissions });
            await insertActivity(
                client,
                "setup",
                `${access.wasCreated ? "Added" : "Updated"} portal user ${email} for ${accountName}`,
                [
                    `Company ${accountName}.`,
                    isActive ? "Portal access active." : "Portal access disabled.",
                    portalPermissions ? "Portal permissions updated." : "",
                    password ? `Portal password ${access.wasCreated ? "created" : "reset"} by warehouse admin.` : "Portal user details updated."
                ].filter(Boolean).join(" ")
            );
            return access;
        });

        const welcomeEmail = {
            attempted: false,
            sent: false,
            recipients: [],
            provider: "",
            error: ""
        };
        if (sendWelcomeEmail && isActive && password.trim()) {
            welcomeEmail.attempted = true;
            try {
                const emailResult = await sendPortalAccessWelcomeEmail({
                    accountName,
                    email,
                    password,
                    portalUrl: buildPortalLoginUrl(req),
                    wasCreated: savedAccess.wasCreated === true
                });
                welcomeEmail.sent = true;
                welcomeEmail.recipients = [email];
                welcomeEmail.provider = emailResult.provider || getConfiguredEmailProvider() || "";
                await withTransaction((client) => insertActivity(
                    client,
                    "email",
                    `Sent portal welcome email to ${email}`,
                    [
                        `Company ${accountName}.`,
                        savedAccess.wasCreated === true ? "New portal user." : "Portal password reset."
                    ].join(" ")
                ));
            } catch (emailError) {
                welcomeEmail.error = emailError?.message || "Welcome email could not be sent.";
                console.error(`Portal welcome email failed for ${email}:`, emailError);
                await withTransaction((client) => insertActivity(
                    client,
                    "email",
                    `Portal welcome email failed for ${email}`,
                    [
                        `Company ${accountName}.`,
                        welcomeEmail.error
                    ].join(" ")
                ));
            }
        }

        res.json({
            success: true,
            access: mapPortalAccessRow(savedAccess),
            wasCreated: savedAccess.wasCreated === true,
            welcomeEmail
        });
    } catch (error) {
        next(error);
    }
});

