app.post("/api/portal/orders/:id/release", async (req, res, next) => {
    try {
        const session = await requirePortalSession(req);
        assertCompanyFeatureEnabledForOwnerRow(session.accessRow, COMPANY_FEATURE_KEYS.ORDER_ENTRY);
        const orderId = toPositiveInt(req.params.id);
        if (!orderId) {
            throw httpError(400, "A valid order id is required.");
        }
        const releaseOptions = sanitizePortalOrderReleaseOptions(req.body);
        const order = await withTransaction(async (client) => {
            if (releaseOptions.shippingLabelAttached) {
                await assertPortalOrderHasCustomerDocuments(client, orderId, session.access.accountName);
            }
            return releasePortalOrder(client, session.accessRow, orderId);
        });
        const releaseActions = {
            warehouseEmailRequested: releaseOptions.notifyWarehouse,
            warehouseEmailSent: false,
            warehouseEmailScheduled: false,
            warehouseEmailScheduledAt: "",
            warehouseEmailDelayMinutes: PORTAL_ORDER_PICK_TICKET_EMAIL_DELAY_MINUTES,
            warehouseRecipients: [],
            ccRecipients: [...releaseOptions.ccEmails],
            warehouseEmailError: ""
        };

        if (releaseOptions.notifyWarehouse) {
            try {
                const scheduleResult = await schedulePortalOrderReleaseEmailForSend(order, {
                    ccRecipients: releaseOptions.ccEmails,
                    actorLabel: session.access.email || "Company portal",
                    reason: "Customer portal release"
                });
                releaseActions.warehouseEmailScheduled = true;
                releaseActions.warehouseEmailScheduledAt = scheduleResult.scheduledAt;
                releaseActions.warehouseRecipients = scheduleResult.recipients;
                releaseActions.ccRecipients = scheduleResult.ccRecipients;
            } catch (error) {
                releaseActions.warehouseEmailError = error?.message || "The warehouse email could not be scheduled.";
                try {
                    await withTransaction((client) => insertActivity(
                        client,
                        "order",
                        `Warehouse order notification schedule failed for portal order ${order.orderCode}`,
                        [
                            order.accountName,
                            releaseActions.warehouseEmailError,
                            session.access.email || "Company portal"
                        ].filter(Boolean).join(" | ")
                    ));
                } catch (logError) {
                    console.error(`Unable to record warehouse release email failure for portal order ${order.orderCode}:`, logError);
                }
            }
        }

        res.json({ success: true, order, releaseActions });
    } catch (error) {
        if (error.statusCode === 401) {
            clearPortalSessionCookie(res, req);
        }
        next(error);
    }
});

app.post("/api/admin/portal-orders/:id/status", requireMobileWorkerAction(), async (req, res, next) => {
    try {
        const orderId = toPositiveInt(req.params.id);
        const nextStatus = normalizePortalOrderStatus(req.body?.status);
        if (!orderId) {
            throw httpError(400, "A valid order id is required.");
        }
        if (!nextStatus) {
            throw httpError(400, "A valid order status is required.");
        }

        let previousOrderStatus = "";
        const order = await withTransaction(async (client) => {
            const accountName = await getPortalOrderAccountNameById(client, orderId);
            await assertAppUserCompanyAccess(client, req.appUser, accountName);
            await assertAssignedMobileTaskForWorker(client, req, {
                sourceType: "PORTAL_ORDER",
                sourceId: orderId,
                taskTypes: taskTypesForPortalOrderStatus(nextStatus),
                permission: RBAC_PERMISSIONS.ORDER_STATUS_UPDATE
            });
            if (nextStatus === "SHIPPED") {
                const currentOrder = await getPortalOrderById(client, orderId, accountName);
                previousOrderStatus = currentOrder?.status || "";
            }
            return updateAdminPortalOrderStatus(client, orderId, nextStatus, req.body, req.appUser);
        });

        const shipmentEmailQueued = nextStatus === "SHIPPED"
            && ["SCHEDULED", "SENDING"].includes(normalizeText(order.shipmentEmailStatus || ""));
        const storeShipmentConfirmationQueued = nextStatus === "SHIPPED";
        res.json({ success: true, order, shipmentEmailQueued, storeShipmentConfirmationQueued });
        if (shipmentEmailQueued) {
            queuePortalShipmentConfirmationEmail(order);
            queueStoreShipmentConfirmation(order, req.body, { isUpdate: previousOrderStatus === "SHIPPED" });
        }
    } catch (error) {
        next(error);
    }
});

