async function sendDeliveryAppointmentRequestEmail(client, appointment, approvalToken, { requestOrigin = "" } = {}) {
    const recipients = await getPortalDeliveryAppointmentRecipients(client, appointment.accountName);
    if (!recipients.length) {
        throw httpError(400, "No warehouse appointment recipient is configured for this company.");
    }
    const actionUrl = buildDeliveryAppointmentActionUrl(appointment, approvalToken, requestOrigin);
    await sendSystemEmail({
        from: SMTP_FROM,
        to: recipients.join(", "),
        replyTo: SMTP_REPLY_TO || undefined,
        subject: `Delivery Appointment Requested - ${appointment.appointmentCode}`,
        text: buildDeliveryAppointmentWarehouseEmailText(appointment, actionUrl),
        html: buildDeliveryAppointmentWarehouseEmailHtml(appointment, actionUrl),
        emailContext: {
            accountName: appointment.accountName,
            sourceType: "DELIVERY_APPOINTMENT_REQUEST",
            sourceRef: appointment.appointmentCode || appointment.id
        }
    }, "Delivery appointment email cannot send because system email is not configured. Set RESEND_API_KEY, SENDGRID_API_KEY, or SMTP settings first.");
    return recipients;
}

async function sendDeliveryAppointmentCustomerEmail(client, appointment) {
    const recipients = new Set();
    addValidEmailRecipient(recipients, appointment.contactEmail);
    (await getPortalShipmentRecipients(client, appointment.accountName)).forEach((email) => addValidEmailRecipient(recipients, email));
    if (!recipients.size) {
        throw httpError(400, "No customer email recipient is configured for this appointment.");
    }
    await sendSystemEmail({
        from: SMTP_FROM,
        to: [...recipients].join(", "),
        replyTo: SMTP_REPLY_TO || undefined,
        subject: appointment.status === "APPROVED"
            ? `Delivery Appointment Approved - ${appointment.appointmentCode}`
            : `Delivery Appointment Alternative Needed - ${appointment.appointmentCode}`,
        text: buildDeliveryAppointmentCustomerEmailText(appointment),
        html: buildDeliveryAppointmentCustomerEmailHtml(appointment),
        emailContext: {
            accountName: appointment.accountName,
            sourceType: "DELIVERY_APPOINTMENT_CUSTOMER",
            sourceRef: appointment.appointmentCode || appointment.id
        }
    }, "Delivery appointment customer email cannot send because system email is not configured. Set RESEND_API_KEY, SENDGRID_API_KEY, or SMTP settings first.");
    return [...recipients];
}

function queueDeliveryAppointmentRequestEmail(appointment, approvalToken, { requestOrigin = "" } = {}) {
    if (!appointment?.id || !appointment?.accountName || !approvalToken) return;
    const appointmentLabel = appointment.appointmentCode || String(appointment.id);
    setTimeout(async () => {
        try {
            const recipients = await sendDeliveryAppointmentRequestEmail(pool, appointment, approvalToken, { requestOrigin });
            await withTransaction((client) => insertActivity(
                client,
                "receipt",
                `Delivery appointment request email sent for ${appointmentLabel}`,
                [appointment.accountName, `Sent to ${formatCount(recipients.length, "recipient")}`].join(" | ")
            ));
        } catch (error) {
            console.error(`Delivery appointment request email failed for ${appointmentLabel}:`, error);
            try {
                await withTransaction((client) => insertActivity(
                    client,
                    "receipt",
                    `Delivery appointment request email failed for ${appointmentLabel}`,
                    [appointment.accountName, error.message || "Unknown email error"].join(" | ")
                ));
            } catch (logError) {
                console.error(`Unable to record delivery appointment email failure for ${appointmentLabel}:`, logError);
            }
        }
    }, 0);
}

async function getPortalOrderReleaseAssignedUsers(client = pool, accountName = "") {
    const normalizedAccount = normalizeText(accountName);
    if (!normalizedAccount) return [];

    const assignedUsers = await client.query(
        `
            select distinct
                u.id,
                u.full_name,
                u.email,
                u.role,
                u.is_active,
                exists (
                    select 1
                    from app_user_company_access direct_access
                    where direct_access.app_user_id = u.id
                      and direct_access.account_name = $1
                ) as direct_company_access,
                exists (
                    select 1
                    from app_user_fulfillment_location_access location_access
                    join company_fulfillment_locations cfl on cfl.fulfillment_location_id = location_access.fulfillment_location_id
                    join fulfillment_locations fl on fl.id = cfl.fulfillment_location_id
                    where location_access.app_user_id = u.id
                      and cfl.account_name = $1
                      and cfl.allow_outbound = true
                      and fl.is_active = true
                ) as warehouse_location_access,
                exists (
                    select 1
                    from company_fulfillment_locations cfl
                    join fulfillment_locations fl on fl.id = cfl.fulfillment_location_id
                    where cfl.account_name = $1
                      and cfl.allow_outbound = true
                      and fl.is_active = true
                      and lower(btrim(coalesce(fl.contact_email, ''))) = lower(btrim(u.email))
                      and btrim(coalesce(fl.contact_email, '')) <> ''
                ) as fulfillment_contact_access
            from app_users u
            where u.is_active = true
              and u.email is not null
              and btrim(u.email) <> ''
              and lower(coalesce(u.role, '')) <> 'super_admin'
              and (
                exists (
                    select 1
                    from app_user_company_access direct_access
                    where direct_access.app_user_id = u.id
                      and direct_access.account_name = $1
                )
                or exists (
                    select 1
                    from app_user_fulfillment_location_access location_access
                    join company_fulfillment_locations cfl on cfl.fulfillment_location_id = location_access.fulfillment_location_id
                    join fulfillment_locations fl on fl.id = cfl.fulfillment_location_id
                    where location_access.app_user_id = u.id
                      and cfl.account_name = $1
                      and cfl.allow_outbound = true
                      and fl.is_active = true
                )
                or exists (
                    select 1
                    from company_fulfillment_locations cfl
                    join fulfillment_locations fl on fl.id = cfl.fulfillment_location_id
                    where cfl.account_name = $1
                      and cfl.allow_outbound = true
                      and fl.is_active = true
                      and lower(btrim(coalesce(fl.contact_email, ''))) = lower(btrim(u.email))
                      and btrim(coalesce(fl.contact_email, '')) <> ''
                )
              )
            order by u.full_name asc, u.email asc
        `,
        [normalizedAccount]
    );
    return assignedUsers.rows;
}

async function getPortalOrderReleaseFulfillmentLocations(client = pool, accountName = "") {
    const normalizedAccount = normalizeText(accountName);
    if (!normalizedAccount) return [];

    const fulfillmentLocations = await client.query(
        `
            select
                cfl.id as assignment_id,
                cfl.account_name,
                cfl.is_primary,
                cfl.allow_inbound,
                cfl.allow_outbound,
                cfl.allow_storage,
                cfl.allow_returns,
                fl.id as fulfillment_location_id,
                fl.code,
                fl.name,
                fl.partner_name,
                fl.location_type,
                fl.contact_name,
                fl.contact_email,
                fl.contact_phone,
                fl.address1,
                fl.address2,
                fl.city,
                fl.state,
                fl.postal_code,
                fl.country,
                fl.is_active
            from company_fulfillment_locations cfl
            join fulfillment_locations fl on fl.id = cfl.fulfillment_location_id
            where cfl.account_name = $1
              and cfl.allow_outbound = true
              and fl.is_active = true
            order by cfl.is_primary desc, fl.is_default desc, fl.code asc
        `,
        [normalizedAccount]
    );
    return fulfillmentLocations.rows;
}

async function getPortalFulfillmentLocationsForAccount(client = pool, accountName = "", { direction = "" } = {}) {
    const normalizedAccount = normalizeText(accountName);
    if (!normalizedAccount) return [];
    const normalizedDirection = normalizeText(direction);
    const clauses = [
        "cfl.account_name = $1",
        "fl.is_active = true"
    ];
    if (normalizedDirection === "INBOUND") clauses.push("cfl.allow_inbound = true");
    if (normalizedDirection === "OUTBOUND") clauses.push("cfl.allow_outbound = true");
    const result = await client.query(
        `
            select
                cfl.id as assignment_id,
                cfl.account_name,
                cfl.is_primary,
                cfl.allow_inbound,
                cfl.allow_outbound,
                cfl.allow_storage,
                cfl.allow_returns,
                fl.id as fulfillment_location_id,
                fl.code,
                fl.name,
                fl.partner_name,
                fl.location_type,
                fl.contact_name,
                fl.contact_email,
                fl.contact_phone,
                fl.address1,
                fl.address2,
                fl.city,
                fl.state,
                fl.postal_code,
                fl.country,
                fl.is_active
            from company_fulfillment_locations cfl
            join fulfillment_locations fl on fl.id = cfl.fulfillment_location_id
            where ${clauses.join(" and ")}
            order by cfl.is_primary desc, fl.is_default desc, fl.code asc
        `,
        [normalizedAccount]
    );
    return result.rows.map(mapCompanyFulfillmentLocationRow);
}

async function resolvePortalFulfillmentLocation(client, accountName, input = {}, { direction = "OUTBOUND", requiredLabel = "warehouse" } = {}) {
    const normalizedAccount = normalizeText(accountName);
    const normalizedDirection = normalizeText(direction);
    const locations = await getPortalFulfillmentLocationsForAccount(client, normalizedAccount, { direction: normalizedDirection });
    if (!locations.length) {
        throw httpError(400, `No active ${requiredLabel} is assigned to this company.`);
    }
    const requestedId = toPositiveInt(input?.fulfillmentLocationId || input?.fulfillment_location_id || input?.warehouseId || input?.warehouse_id);
    const requestedCode = normalizeText(input?.fulfillmentLocationCode || input?.fulfillment_location_code || input?.warehouseCode || input?.warehouse_code || input?.warehouse);
    if (requestedId || requestedCode) {
        const match = locations.find((location) => {
            return (requestedId && toPositiveInt(location.fulfillmentLocationId) === requestedId)
                || (requestedCode && normalizeText(location.locationCode) === requestedCode);
        });
        if (!match) {
            throw httpError(400, `Choose a valid ${requiredLabel} assigned to this company.`);
        }
        return match;
    }
    if (locations.length > 1) {
        throw httpError(400, `Choose the ${requiredLabel} for this transaction.`);
    }
    return locations[0];
}

function addValidEmailRecipient(recipients, value) {
    const email = normalizeEmail(value);
    if (email && isValidEmailAddress(email) && !email.endsWith(".local")) {
        recipients.add(email);
    }
}

function choosePortalReleaseFulfillmentRecipients(rows = []) {
    const withEmail = rows.filter((row) => {
        const email = normalizeEmail(row.contact_email || "");
        return email && isValidEmailAddress(email) && !email.endsWith(".local");
    });
    const primaryRows = withEmail.filter((row) => row.is_primary === true);
    return primaryRows.length ? primaryRows : withEmail;
}

function normalizeRecipientRows(rows = [], emailField = "email") {
    const recipients = [];
    const seen = new Set();
    rows.forEach((row) => {
        const email = normalizeEmail(row?.[emailField] || "");
        if (!email || !isValidEmailAddress(email) || email.endsWith(".local") || seen.has(email)) return;
        seen.add(email);
        recipients.push(email);
    });
    return recipients;
}

async function getPortalOrderReleaseRecipients(client = pool, accountName = "") {
    const normalizedAccount = normalizeText(accountName);
    const recipients = new Set();

    if (normalizedAccount) {
        const assignedUsers = await getPortalOrderReleaseAssignedUsers(client, normalizedAccount);
        assignedUsers.forEach((row) => addValidEmailRecipient(recipients, row.email));

        const fulfillmentLocations = await getPortalOrderReleaseFulfillmentLocations(client, normalizedAccount);
        choosePortalReleaseFulfillmentRecipients(fulfillmentLocations)
            .forEach((row) => addValidEmailRecipient(recipients, row.contact_email));
    }

    if (!recipients.size) {
        normalizeEmailList(ORDER_RELEASE_TO).forEach((email) => addValidEmailRecipient(recipients, email));
    }
    if (!recipients.size) {
        addValidEmailRecipient(recipients, SMTP_REPLY_TO);
        addValidEmailRecipient(recipients, DEMO_REQUEST_TO);
        addValidEmailRecipient(recipients, DEFAULT_ADMIN_EMAIL);
    }

    return [...recipients];
}

async function getLatestPortalOrderForReleaseEmailTest(client = pool, accountName = "") {
    const normalizedAccount = normalizeText(accountName);
    if (!normalizedAccount) return null;
    const result = await client.query(
        `
            select id
            from portal_orders
            where account_name = $1
              and status <> 'ARCHIVED'
            order by
              coalesce(released_at, shipped_at, staged_at, picked_at, updated_at, created_at) desc,
              id desc
            limit 1
        `,
        [normalizedAccount]
    );
    if (result.rowCount !== 1) return null;
    return getPortalOrderById(client, result.rows[0].id, normalizedAccount);
}

async function getCompanyEmailFlowCheck(client = pool, accountName = "") {
    const normalizedAccount = normalizeText(accountName);
    if (!normalizedAccount) {
        throw httpError(400, "Choose a company to check its email flow.");
    }

    const [ownerResult, assignedUsers, fulfillmentLocations, shipmentRecipients] = await Promise.all([
        client.query(
            `
                select name, email, billing_email, ap_email, portal_login_email, is_active
                from owner_accounts
                where name = $1
                limit 1
            `,
            [normalizedAccount]
        ),
        getPortalOrderReleaseAssignedUsers(client, normalizedAccount),
        getPortalOrderReleaseFulfillmentLocations(client, normalizedAccount),
        getPortalShipmentRecipients(client, normalizedAccount)
    ]);

    const selectedFulfillmentRecipients = choosePortalReleaseFulfillmentRecipients(fulfillmentLocations);
    const assignedUserRecipients = normalizeRecipientRows(assignedUsers, "email");
    const fulfillmentRecipients = normalizeRecipientRows(selectedFulfillmentRecipients, "contact_email");
    const orderReleaseFallbackRecipients = normalizeEmailList(ORDER_RELEASE_TO);
    const systemFallbackRecipients = normalizeEmailList([SMTP_REPLY_TO, DEMO_REQUEST_TO, DEFAULT_ADMIN_EMAIL].filter(Boolean).join(","));
    const releaseRecipients = await getPortalOrderReleaseRecipients(client, normalizedAccount);
    const warnings = [];

    if (!ownerResult.rowCount) {
        warnings.push("This company is not saved in Company Setup yet.");
    }
    if (!hasSystemEmailConfig()) {
        warnings.push("System email is not configured. Set RESEND_API_KEY, SENDGRID_API_KEY, or SMTP settings before live notifications can send.");
    }
    if (!assignedUserRecipients.length) {
        warnings.push("No active warehouse user is assigned to this company.");
    }
    if (!fulfillmentRecipients.length) {
        warnings.push("No outbound fulfillment location contact email is configured for this company.");
    }
    if (!releaseRecipients.length) {
        warnings.push("No release recipients could be resolved.");
    }

    let releaseRecipientSource = "Not configured";
    if (assignedUserRecipients.length && fulfillmentRecipients.length) {
        releaseRecipientSource = "Assigned warehouse users + fulfillment location contact";
    } else if (assignedUserRecipients.length) {
        releaseRecipientSource = "Assigned warehouse users";
    } else if (fulfillmentRecipients.length) {
        releaseRecipientSource = "Fulfillment location contact";
    } else if (orderReleaseFallbackRecipients.length) {
        releaseRecipientSource = "ORDER_RELEASE_TO fallback";
        warnings.push("Release email is using ORDER_RELEASE_TO because no company-specific warehouse route is configured.");
    } else if (systemFallbackRecipients.length) {
        releaseRecipientSource = "System/admin fallback";
        warnings.push("Release email is falling back to support/admin because no warehouse route is configured for this company.");
    }

    const selectedFulfillmentIds = new Set(selectedFulfillmentRecipients.map((row) => String(row.assignment_id)));

    return {
        accountName: normalizedAccount,
        checkedAt: new Date().toISOString(),
        build: APP_BUILD_INFO.label,
        emailProvider: getConfiguredEmailProvider() || "Not configured",
        systemEmailConfigured: hasSystemEmailConfig(),
        from: SMTP_FROM,
        replyTo: SMTP_REPLY_TO,
        releaseRecipientSource,
        releaseRecipients,
        shipmentRecipients,
        assignedWarehouseUsers: assignedUsers.map((row) => ({
            id: String(row.id),
            fullName: row.full_name || "",
            email: row.email || "",
            role: row.role || "",
            isActive: row.is_active !== false,
            directCompanyAccess: row.direct_company_access === true,
            warehouseLocationAccess: row.warehouse_location_access === true,
            fulfillmentContactAccess: row.fulfillment_contact_access === true
        })),
        fulfillmentLocations: fulfillmentLocations.map((row) => ({
            assignmentId: String(row.assignment_id),
            fulfillmentLocationId: String(row.fulfillment_location_id),
            code: row.code || "",
            name: row.name || "",
            partnerName: row.partner_name || "",
            locationType: row.location_type || "",
            contactName: row.contact_name || "",
            contactEmail: row.contact_email || "",
            contactPhone: row.contact_phone || "",
            address1: row.address1 || "",
            address2: row.address2 || "",
            city: row.city || "",
            state: row.state || "",
            postalCode: row.postal_code || "",
            country: row.country || "",
            isPrimary: row.is_primary === true,
            allowOutbound: row.allow_outbound !== false,
            willReceiveReleaseEmail: selectedFulfillmentIds.has(String(row.assignment_id))
        })),
        ownerAccount: ownerResult.rowCount ? {
            name: ownerResult.rows[0].name || "",
            email: ownerResult.rows[0].email || "",
            billingEmail: ownerResult.rows[0].billing_email || "",
            apEmail: ownerResult.rows[0].ap_email || "",
            portalLoginEmail: ownerResult.rows[0].portal_login_email || "",
            isActive: ownerResult.rows[0].is_active !== false
        } : null,
        fallbackRecipients: {
            orderReleaseTo: orderReleaseFallbackRecipients,
            systemFallback: systemFallbackRecipients
        },
        warnings
    };
}

