function pdfSafeText(value) {
    return String(value || "")
        .replace(/[^\x20-\x7E]/g, " ")
        .replace(/\s+/g, " ")
        .trim();
}

function pdfEscapeText(value) {
    return pdfSafeText(value).replace(/\\/g, "\\\\").replace(/\(/g, "\\(").replace(/\)/g, "\\)");
}

function wrapPdfText(value, width = 92) {
    const words = pdfSafeText(value).split(/\s+/).filter(Boolean);
    const lines = [];
    let current = "";
    words.forEach((word) => {
        const next = current ? `${current} ${word}` : word;
        if (next.length > width && current) {
            lines.push(current);
            current = word;
        } else if (word.length > width) {
            if (current) lines.push(current);
            for (let index = 0; index < word.length; index += width) {
                lines.push(word.slice(index, index + width));
            }
            current = "";
        } else {
            current = next;
        }
    });
    if (current) lines.push(current);
    return lines.length ? lines : [""];
}

function buildSimpleTextPdfBuffer(lines = []) {
    const pageWidth = 612;
    const pageHeight = 792;
    const marginX = 42;
    const marginTop = 42;
    const lineHeight = 14;
    const maxLinesPerPage = Math.floor((pageHeight - (marginTop * 2)) / lineHeight);
    const sourceLines = Array.isArray(lines) && lines.length ? lines : ["WMS365 Document"];
    const pages = [];

    for (let index = 0; index < sourceLines.length; index += maxLinesPerPage) {
        pages.push(sourceLines.slice(index, index + maxLinesPerPage));
    }

    const objects = [
        { body: "<< /Type /Catalog /Pages 2 0 R >>" },
        { body: "" },
        { body: "<< /Type /Font /Subtype /Type1 /BaseFont /Courier >>" }
    ];
    const pageObjectIds = [];

    pages.forEach((pageLines) => {
        const operations = ["BT", "/F1 10 Tf", "12 TL"];
        pageLines.forEach((line, lineIndex) => {
            const y = pageHeight - marginTop - (lineIndex * lineHeight);
            operations.push(`1 0 0 1 ${marginX} ${y} Tm`);
            operations.push(`(${pdfEscapeText(line)}) Tj`);
        });
        operations.push("ET");
        const stream = operations.join("\n");
        const contentObjectId = objects.length + 1;
        const pageObjectId = contentObjectId + 1;
        objects.push({
            body: `<< /Length ${Buffer.byteLength(stream, "utf8")} >>\nstream\n${stream}\nendstream`
        });
        objects.push({
            body: `<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ${pageWidth} ${pageHeight}] /Resources << /Font << /F1 3 0 R >> >> /Contents ${contentObjectId} 0 R >>`
        });
        pageObjectIds.push(pageObjectId);
    });

    objects[1].body = `<< /Type /Pages /Kids [${pageObjectIds.map((id) => `${id} 0 R`).join(" ")}] /Count ${pageObjectIds.length} >>`;

    let output = "%PDF-1.4\n";
    const offsets = [0];
    objects.forEach((object, index) => {
        offsets.push(Buffer.byteLength(output, "utf8"));
        output += `${index + 1} 0 obj\n${object.body}\nendobj\n`;
    });
    const xrefOffset = Buffer.byteLength(output, "utf8");
    output += `xref\n0 ${objects.length + 1}\n`;
    output += "0000000000 65535 f \n";
    for (let index = 1; index < offsets.length; index += 1) {
        output += `${String(offsets[index]).padStart(10, "0")} 00000 n \n`;
    }
    output += `trailer\n<< /Size ${objects.length + 1} /Root 1 0 R >>\nstartxref\n${xrefOffset}\n%%EOF\n`;
    return Buffer.from(output, "utf8");
}

function formatPickTicketLocationText(line) {
    const locations = Array.isArray(line?.pickLocations) ? line.pickLocations : [];
    if (!locations.length) return "No location found";
    return locations.map((entry) => [
        entry.location || "",
        formatTrackedQuantity(entry.quantity || line.quantity || 0, entry.trackingLevel || line.trackingLevel),
        entry.lotNumber ? `Lot ${entry.lotNumber}` : "",
        entry.expirationDate ? `Exp ${entry.expirationDate}` : ""
    ].filter(Boolean).join(" | ")).join("; ");
}

function formatPickTicketWorkflowStatus(order) {
    const status = String(order?.status || "").toUpperCase();
    if (status === "RELEASED") return "READY TO PICK";
    return status || "READY TO PICK";
}

function buildPortalOrderPickTicketPdfAttachment(order) {
    const lines = [
        "WMS365 PICK TICKET",
        "",
        `Order: ${order.orderCode || ""}`,
        `Company: ${order.accountName || ""}`,
        `Pick Status: ${formatPickTicketWorkflowStatus(order)}`,
        `PO Number: ${order.poNumber || "-"}`,
        `Shipping Reference: ${order.shippingReference || "-"}`,
        `Requested Ship Date: ${order.requestedShipDate || "-"}`,
        "",
        `Customer Contact: ${[order.contactName, order.contactPhone].filter(Boolean).join(" | ") || "-"}`,
        "Ship To:"
    ];

    formatPortalOrderShipToAddress(order)
        .split("|")
        .map((line) => line.trim())
        .filter(Boolean)
        .forEach((line) => lines.push(`  ${line}`));

    if (order.orderNotes) {
        lines.push("", "Order Notes:");
        wrapPdfText(order.orderNotes, 88).forEach((line) => lines.push(`  ${line}`));
    }

    lines.push("", "Order Lines:", "LN  SKU                 QTY            PICK LOCATION / LOT / EXPIRATION", "--- ------------------- -------------- -----------------------------------------------");
    (order.lines || []).forEach((line, index) => {
        const linePrefix = `${String(index + 1).padEnd(3)} ${pdfSafeText(line.sku).slice(0, 19).padEnd(19)} ${pdfSafeText(formatTrackedQuantity(line.quantity, line.trackingLevel)).slice(0, 14).padEnd(14)} `;
        const locationLines = wrapPdfText(formatPickTicketLocationText(line), 47);
        lines.push(`${linePrefix}${locationLines[0] || ""}`);
        locationLines.slice(1).forEach((locationLine) => lines.push(`${"".padEnd(41)}${locationLine}`));
        const detailText = [line.description, line.upc ? `UPC ${line.upc}` : ""].filter(Boolean).join(" | ");
        if (detailText) {
            wrapPdfText(detailText, 88).forEach((detailLine) => lines.push(`    ${detailLine}`));
        }
    });

    lines.push(
        "",
        "Warehouse Pick Verification - print name and date clearly:",
        "",
        "Picked by: ____________________________________  Date: ________________",
        "",
        "Verified by: __________________________________  Date: ________________"
    );

    lines.push("", `Generated: ${new Date().toISOString()}`);

    return {
        filename: normalizeUploadFileName(`wms365-${order.orderCode || "order"}-pick-ticket.pdf`),
        content: buildSimpleTextPdfBuffer(lines),
        contentType: "application/pdf"
    };
}

async function getPortalOrderReleaseDocumentAttachments(orderId, client = pool) {
    const normalizedOrderId = toPositiveInt(orderId);
    if (!normalizedOrderId) return [];
    const result = await client.query(
        `
            select id, file_name, file_type, file_size, file_data
            from portal_order_documents
            where order_id = $1
            order by created_at asc, id asc
        `,
        [normalizedOrderId]
    );
    return result.rows
        .filter((row) => !isPortalOrderReleaseCopyDocument(row))
        .map((row) => ({
            filename: normalizeUploadFileName(row.file_name || `order-document-${row.id}`),
            content: row.file_data,
            contentType: row.file_type || "application/octet-stream",
            fileSize: Number(row.file_size) || Number(row.file_data?.length) || 0
        }))
        .filter((attachment) => attachment.filename && attachment.content);
}

async function getPortalOrderShipmentDocumentAttachments(orderId, client = pool) {
    const storedAttachments = await getPortalOrderReleaseDocumentAttachments(orderId, client);
    return storedAttachments
        .map((attachment) => ({
            fileName: attachment.filename,
            fileBuffer: attachment.content,
            fileType: attachment.contentType,
            fileSize: attachment.fileSize
        }))
        .filter((attachment) => attachment.fileName && attachment.fileBuffer);
}

async function sendPortalOrderReleaseEmail(order, { ccRecipients = [], subjectPrefix = "", testMode = false, testRequestedBy = "" } = {}) {
    if (!hasSystemEmailConfig()) {
        throw httpError(500, "Warehouse email is not configured yet. Set RESEND_API_KEY, SENDGRID_API_KEY, or SMTP settings first.");
    }

    const recipients = await getPortalOrderReleaseRecipients(pool, order.accountName);
    if (!recipients.length) {
        throw httpError(400, "No warehouse notification email is configured. Assign an active warehouse user to this company, or set ORDER_RELEASE_TO or SMTP_REPLY_TO.");
    }

    const normalizedCcRecipients = normalizeEmailList(ccRecipients).filter((email) => !recipients.includes(email));
    await sendSystemEmail({
        from: SMTP_FROM,
        to: recipients.join(", "),
        cc: normalizedCcRecipients.length ? normalizedCcRecipients.join(", ") : undefined,
        replyTo: SMTP_REPLY_TO || undefined,
        subject: `${subjectPrefix || ""}Order Released - ${order.orderCode} - ${order.accountName}`,
        text: buildPortalReleaseEmailText(order, { ccRecipients: normalizedCcRecipients, testMode, testRequestedBy }),
        html: buildPortalReleaseEmailHtml(order, { ccRecipients: normalizedCcRecipients, testMode, testRequestedBy }),
        emailContext: {
            accountName: order.accountName,
            sourceType: testMode ? "PORTAL_ORDER_TEST" : "PORTAL_ORDER",
            sourceRef: order.orderCode || order.id
        }
    }, "Warehouse email is not configured yet. Set RESEND_API_KEY, SENDGRID_API_KEY, or SMTP settings first.");

    return {
        recipients,
        ccRecipients: normalizedCcRecipients,
        attachments: []
    };
}

function formatKittingRequestSummary(request) {
    const components = Array.isArray(request.components) ? request.components : [];
    if (components.length > 1) {
        return `${components.length} component SKUs to ${request.targetQuantity} of ${request.targetSku}`;
    }
    return [
        `${request.sourceQuantity} of ${request.sourceSku}`,
        "to",
        `${request.targetQuantity} of ${request.targetSku}`
    ].join(" ");
}

function formatKittingComponentLines(request) {
    const components = Array.isArray(request.components) && request.components.length
        ? request.components
        : [{ sku: request.sourceSku, totalQuantity: request.sourceQuantity, description: request.sourceDescription || "" }];
    return components.map((component) => {
        const parts = [
            component.sku,
            component.totalQuantity ? `Total ${component.totalQuantity}` : "",
            component.quantityPerUnit ? `${component.quantityPerUnit} per display` : "",
            component.description || "",
            component.note ? `Note: ${component.note}` : ""
        ].filter(Boolean);
        return `- ${parts.join(" | ")}`;
    }).join("\n");
}

function buildKittingComponentRowsHtml(request) {
    const components = Array.isArray(request.components) && request.components.length
        ? request.components
        : [{ sku: request.sourceSku, totalQuantity: request.sourceQuantity, description: request.sourceDescription || "" }];
    return components.map((component) => `
        <tr>
            <td style="padding:8px;border:1px solid #e5e7eb;">${escapeHtml(component.sku || "-")}</td>
            <td style="padding:8px;border:1px solid #e5e7eb;">${escapeHtml(String(component.quantityPerUnit || "-"))}</td>
            <td style="padding:8px;border:1px solid #e5e7eb;">${escapeHtml(String(component.totalQuantity || "-"))}</td>
            <td style="padding:8px;border:1px solid #e5e7eb;">${escapeHtml(component.description || "-")}</td>
            <td style="padding:8px;border:1px solid #e5e7eb;">${escapeHtml(component.note || "-")}</td>
        </tr>
    `).join("");
}

function buildPortalKittingRequestEmailText(request) {
    return [
        `Kitting request ${request.requestCode}`,
        `Company: ${request.accountName}`,
        `Status: ${request.status}`,
        `Request: ${formatKittingRequestSummary(request)}`,
        "",
        "Components to pull:",
        formatKittingComponentLines(request),
        "",
        `Finished Display SKU: ${request.targetSku}`,
        `Displays to Build: ${request.targetQuantity}`,
        request.salesOrderReference ? `Sales Order: ${request.salesOrderReference}` : "",
        request.purchaseOrderReference ? `Purchase Order: ${request.purchaseOrderReference}` : "",
        request.requestedCompletionDate ? `Needed By: ${request.requestedCompletionDate}` : "",
        request.requestedByEmail || request.requestedByName ? `Requested By: ${[request.requestedByName, request.requestedByEmail].filter(Boolean).join(" | ")}` : "",
        request.targetDescription ? `Finished Item Description: ${request.targetDescription}` : "",
        request.notes ? `Notes: ${request.notes}` : "",
        "",
        "Warehouse action required: review the request, complete the physical kitting/re-SKU work, then use the warehouse Convert Item process to update inventory."
    ].filter(Boolean).join("\n");
}

