function normalizePortalOrderDocumentCategory(value) {
    const normalized = normalizeText(value || "").replace(/[\s-]+/g, "_");
    if (!normalized) return PORTAL_ORDER_DOCUMENT_CATEGORIES.GENERAL;
    return Object.values(PORTAL_ORDER_DOCUMENT_CATEGORIES).includes(normalized)
        ? normalized
        : PORTAL_ORDER_DOCUMENT_CATEGORIES.GENERAL;
}

function sanitizePortalShippedLinesInput(lines) {
    return lines.map((line) => {
        const orderLineId = toPositiveInt(line?.orderLineId || line?.order_line_id || line?.lineId || line?.line_id || line?.id);
        const sku = normalizeText(line?.sku || "");
        const shippedQuantityRaw = line?.shippedQuantity ?? line?.shipped_quantity ?? line?.quantity ?? line?.qty;
        const shippedQuantity = Number(shippedQuantityRaw);
        if (!orderLineId && !sku && (shippedQuantityRaw === undefined || shippedQuantityRaw === null || shippedQuantityRaw === "")) return null;
        if (!Number.isInteger(shippedQuantity) || shippedQuantity < 0) {
            throw httpError(400, `Enter a valid shipped quantity for ${sku || "each order line"}.`);
        }
        return {
            orderLineId,
            sku,
            shippedQuantity
        };
    }).filter(Boolean);
}

function sanitizePortalOrderDocumentsInput(documents) {
    if (documents.length > 5) {
        throw httpError(400, "Upload up to 5 documents at a time.");
    }
    return documents.map(sanitizePortalOrderDocumentInput).filter(Boolean);
}

function sanitizePortalOrderDocumentInput(document) {
    if (!document || typeof document !== "object") return null;
    const fileName = normalizeUploadFileName(document.fileName || document.name || document.filename);
    const dataUrl = String(document.dataUrl || document.data || "").trim();
    if (!fileName && !dataUrl) return null;
    if (!fileName || !dataUrl) {
        throw httpError(400, "Each document must include a file and file name.");
    }

    const match = dataUrl.match(/^data:([^;,]+);base64,(.+)$/);
    if (!match) {
        throw httpError(400, `${fileName} could not be processed. Upload a PDF or image file.`);
    }

    const fileType = normalizeSafeUploadMimeType(document.fileType || match[1] || "");
    if (!fileType) throw httpError(400, `${fileName} must be a PDF, JPEG, PNG, or WebP file.`);

    const base64 = match[2].replace(/\s+/g, "");
    if (!base64) {
        throw httpError(400, `${fileName} did not contain file data.`);
    }

    let buffer;
    try {
        buffer = Buffer.from(base64, "base64");
    } catch (_error) {
        throw httpError(400, `${fileName} could not be decoded.`);
    }

    if (!buffer.length) {
        throw httpError(400, `${fileName} did not contain file data.`);
    }
    if (buffer.length > 4 * 1024 * 1024) {
        throw httpError(400, `${fileName} is too large. Keep each document under 4 MB.`);
    }
    assertSafeUploadContent(fileName, fileType, buffer);

    return {
        fileName: ensureSafeUploadFileExtension(fileName, fileType),
        fileType,
        fileSize: buffer.length,
        fileBuffer: buffer,
        documentCategory: normalizePortalOrderDocumentCategory(document.documentCategory || document.document_category || document.category || document.type)
    };
}

function normalizeSafeUploadMimeType(value) {
    const mimeType = normalizeFreeText(value || "").toLowerCase();
    if (mimeType === "image/jpg") return "image/jpeg";
    return SAFE_UPLOAD_MIME_TYPES.has(mimeType) ? mimeType : "";
}

function ensureSafeUploadFileExtension(fileName, mimeType) {
    const safeName = normalizeUploadFileName(fileName) || "document";
    const ext = path.extname(safeName).toLowerCase();
    const expectedExt = SAFE_UPLOAD_EXTENSIONS.get(mimeType) || "";
    if (!expectedExt) return safeName;
    if (mimeType === "image/jpeg" && [".jpg", ".jpeg"].includes(ext)) return safeName;
    return ext === expectedExt ? safeName : `${safeName.replace(/\.[^.]*$/, "")}${expectedExt}`;
}

function bufferStartsWith(buffer, signature) {
    return Buffer.isBuffer(buffer) && buffer.length >= signature.length && signature.every((byte, index) => buffer[index] === byte);
}

function detectSafeUploadMimeType(buffer) {
    if (!Buffer.isBuffer(buffer) || !buffer.length) return "";
    if (bufferStartsWith(buffer, [0x25, 0x50, 0x44, 0x46, 0x2d])) return "application/pdf";
    if (bufferStartsWith(buffer, [0xff, 0xd8, 0xff])) return "image/jpeg";
    if (bufferStartsWith(buffer, [0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a])) return "image/png";
    if (buffer.length >= 12 && buffer.toString("ascii", 0, 4) === "RIFF" && buffer.toString("ascii", 8, 12) === "WEBP") return "image/webp";
    return "";
}

function assertSafeUploadContent(fileName, declaredMimeType, buffer) {
    const detectedMimeType = detectSafeUploadMimeType(buffer);
    if (!detectedMimeType || detectedMimeType !== declaredMimeType) {
        throw httpError(400, `${fileName} could not be verified as a safe PDF, JPEG, PNG, or WebP file.`);
    }
    const sample = buffer.subarray(0, Math.min(buffer.length, 4096)).toString("utf8").toLowerCase();
    if (sample.includes("<svg") || sample.includes("<script") || sample.includes("<?php") || bufferStartsWith(buffer, [0x4d, 0x5a])) {
        throw httpError(400, `${fileName} contains executable or unsafe content.`);
    }
}

function contentDispositionAttachment(fileName) {
    const safeName = normalizeUploadFileName(fileName) || "document";
    return `attachment; filename="${safeName.replace(/"/g, "")}"`;
}

function contentDispositionInline(fileName) {
    const safeName = normalizeUploadFileName(fileName) || "document";
    return `inline; filename="${safeName.replace(/"/g, "")}"`;
}

function sendSafeUploadedDocument(res, document, { inline = false } = {}) {
    const declaredMimeType = normalizeSafeUploadMimeType(document?.file_type || "");
    const buffer = Buffer.isBuffer(document?.file_data) ? document.file_data : Buffer.from(document?.file_data || "");
    const detectedMimeType = detectSafeUploadMimeType(buffer);
    const mimeType = declaredMimeType && declaredMimeType === detectedMimeType ? declaredMimeType : "application/octet-stream";
    const safeFileName = ensureSafeUploadFileExtension(document?.file_name || "document", mimeType);
    res.setHeader("Content-Type", mimeType);
    res.setHeader("X-Content-Type-Options", "nosniff");
    res.setHeader("Content-Length", String(buffer.length || document?.file_size || 0));
    res.setHeader("Content-Disposition", inline ? contentDispositionInline(safeFileName) : contentDispositionAttachment(safeFileName));
    res.send(buffer);
}

function normalizeUploadFileName(value) {
    return String(value || "")
        .trim()
        .replace(/^.*[\\/]/, "")
        .replace(/[^\w.\- ()[\]]+/g, "_")
        .slice(0, 160);
}

function normalizePortalOrderStatus(value) {
    const normalized = normalizeText(value);
    return ["DRAFT", "RELEASED", "PICKED", "STAGED", "SHIPPED", "CANCELLED", "ARCHIVED"].includes(normalized) ? normalized : "";
}

function normalizePortalInboundStatus(value) {
    const normalized = normalizeText(value);
    return ["SUBMITTED", "ARRIVED", "RECEIVED", "RECEIVED_PENDING_PUTAWAY", "PARTIALLY_PUTAWAY", "PUTAWAY_COMPLETE", "CANCELLED"].includes(normalized) ? normalized : "";
}

function categoryAccountCode(category) {
    const normalized = normalizeText(category);
    if (normalized.includes("LABOUR")) return "5010";
    if (normalized.includes("FREIGHT")) return "5020";
    if (normalized.includes("RENT")) return "5030";
    if (normalized.includes("SUPPLIES")) return "5040";
    return "5000";
}

function normalizeBillingFinanceStatus(value) {
    const normalized = String(value || "").trim().toLowerCase();
    if (["pending", "open"].includes(normalized)) return "pending";
    if (["approved", "approve"].includes(normalized)) return "approved";
    if (["invoiced", "invoice"].includes(normalized)) return "invoiced";
    if (["voided", "void"].includes(normalized)) return "voided";
    return "";
}

function normalizeInvoiceStatus(value) {
    const normalized = String(value || "").trim().toLowerCase().replace(/\s+/g, "_");
    if (["draft", "approved", "sent", "paid", "partial", "overdue", "void", "credit_note"].includes(normalized)) return normalized;
    return "draft";
}

function normalizePaymentMethod(value) {
    const text = normalizeFreeText(value || "EFT");
    const match = BILLING_FINANCE_PAYMENT_METHODS.find((method) => normalizeText(method) === normalizeText(text));
    return match || "EFT";
}

function normalizeCurrencyCode(value, fallback = "CAD") {
    const normalized = normalizeText(value || fallback).replace(/[^A-Z]/g, "").slice(0, 3);
    return normalized || fallback;
}

function roundMoney(value) {
    const numeric = Number.parseFloat(String(value));
    if (!Number.isFinite(numeric)) return 0;
    return Math.round(numeric * 100) / 100;
}

function normalizeMasterCustomerName(value) {
    return normalizeText(value || BILLING_ACCOUNTING_DEFAULT_MASTER_CUSTOMER) || BILLING_ACCOUNTING_DEFAULT_MASTER_CUSTOMER;
}

async function getDefaultMasterCustomer(client) {
    const result = await client.query("select * from master_customers where name = $1 limit 1", [BILLING_ACCOUNTING_DEFAULT_MASTER_CUSTOMER]);
    return result.rows[0] || { id: null, name: BILLING_ACCOUNTING_DEFAULT_MASTER_CUSTOMER };
}

